public abstract class Status {}
public class Active extends Status {}
public class Suspended extends Status {}
// Processing
public String check(Status s) {
    if (s instanceof Active) return "Go";
    if (s instanceof Suspended) return "Stop";
    throw new IllegalArgumentException();
}

